const stdout = $input.first().json.stdout ?? '';
if (!stdout.trim()) throw new Error('bot-lock acquire returned empty stdout');
const lock = JSON.parse(stdout);
if (!lock.acquired) return [];
const input = $input.first().json;
return [{ json: { ...input, telegram_lock_acquired: true, telegram_lock_id: lock.lock_id } }];

const input = $input.first().json;
const body = input.body ?? input;
const payload = {
  ...body,
  telegram_polled: Boolean(input.telegram_polled),
  telegram_command: input.telegram_command ?? body.telegram_command ?? null,
  telegram_lock_acquired: Boolean(input.telegram_lock_acquired),
  telegram_lock_id: input.telegram_lock_id ?? body.telegram_lock_id ?? null
};
return [{
  json: {
    ...payload,
    payload_b64: Buffer.from(JSON.stringify(payload), 'utf8').toString('base64')
  }
}];

const stdout = $input.first().json.stdout ?? '';
if (!stdout.trim()) {
  throw new Error('ingest-run.ts returned empty stdout');
}
return [{ json: JSON.parse(stdout) }];

const data = ($node['Parse Ingest Run Result'] && $node['Parse Ingest Run Result'].json) ? $node['Parse Ingest Run Result'].json : $json;
const staticData = typeof $getWorkflowStaticData === 'function' ? $getWorkflowStaticData('global') : {};
if (data.telegram_polled && Number.isSafeInteger(Number(data.telegram_update_id))) {
  staticData.telegram_last_update_id = Number(data.telegram_update_id);
}
return [{ json: data }];
